-- Update FAQ for pompe-a-chaleur service in specific cities
-- Delete existing FAQ for target cities
DELETE FROM service_city_faqs 
WHERE service_id = (SELECT id FROM services WHERE slug = 'pompe-a-chaleur')
AND city_id IN (
  SELECT id FROM cities WHERE slug IN (
    'marcq-en-baroeul', 'bondues', 'la-madeleine', 
    'lambersart', 'saint-andre-lez-lille', 'lomme'
  )
);

